  digitalWrite(SEG_A,a); digitalWrite(SEG_B,b); digitalWrite(SEG_C,c);
  digitalWrite(SEG_D,d); digitalWrite(SEG_E,e); digitalWrite(SEG_F,f);
  digitalWrite(SEG_G,g);
}

